fix:
private boolean getPivot row( final int column, final int row, final int num rows, final int numColumns, final int numObjective functions, final double[][] tableau) {
    if ( row > num rows || column > numColumns || row == num object functions || column == num object functions ) {
return false;
    }
    double value = tableau[row][column];
    if ( value != 0 ) {
        int num rows = tableau[row].length;
        for ( int i = 0; i < num rows ; i++ ) {
            tableau[row][i] /= value;
        }
    }
    return true;
}

